import React, { useState, useEffect, useMemo } from 'react';

/**
 * ПОРТФОЛИО АЛЕКСАНДРЫ
 * Финальная версия: исправлены предупреждения ESLint и добавлены 
 * гарантированные стили для темного фона.
 */

const Icon = ({ name }) => {
  const icons = {
    telegram: (
      <path d="M12 2C6.48 2 2 6.48 2 12s4.48 10 10 10 10-4.48 10-10S17.52 2 12 2zm4.64 6.8c-.15 1.58-.8 5.42-1.13 7.19-.14.75-.42 1-.68 1.03-.58.05-1.02-.38-1.58-.75-.88-.58-1.38-.94-2.23-1.5-.99-.65-.35-1.01.22-1.59.15-.15 2.71-2.48 2.76-2.69.01-.03.01-.14-.07-.2-.08-.06-.19-.04-.27-.02-.11.02-1.93 1.23-5.46 3.62-.51.35-.98.53-1.39.52-.46-.01-1.33-.26-1.98-.48-.8-.27-1.43-.42-1.37-.89.03-.25.38-.51 1.03-.78 4.04-1.76 6.74-2.92 8.09-3.48 3.85-1.6 4.64-1.88 5.17-1.89.11 0 .37.03.54.17.14.12.18.28.2.45-.02.07-.02.13-.03.19z"/>
    ),
    phone: (
      <path d="M22 16.92v3a2 2 0 0 1-2.18 2 19.79 19.79 0 0 1-8.63-3.07 19.5 19.5 0 0 1-6-6 19.79 19.79 0 0 1-3.07-8.67A2 2 0 0 1 4.11 2h3a2 2 0 0 1 2 1.72 12.84 12.84 0 0 0 .7 2.81 2 2 0 0 1-.45 2.11L8.09 9.91a16 16 0 0 0 6 6l1.27-1.27a2 2 0 0 1 2.11-.45 12.84 12.84 0 0 0 2.81.7A2 2 0 0 1 22 16.92z"/>
    )
  };

  return (
    <svg viewBox="0 0 24 24" width="18" height="18" fill="currentColor">
      {icons[name] || null}
    </svg>
  );
};

const App = () => {
  const [filter, setFilter] = useState('Все');
  const [isScrolled, setIsScrolled] = useState(false);
  const [showArchive, setShowArchive] = useState(false);

  const themeStyles = {
    background: '#0d0d0f',
    text: '#e0e0e6',
    accent: '#ffb3d9'
  };

  const categories = ['Все', 'Айдентика', 'Логотипы', 'Веб-дизайн', 'Печатная графика'];

  const projects = useMemo(() => ({
    featured: [
      { id: 'f1', title: "Проект айдентики", cat: "Айдентика", year: 2025, img: "https://images.unsplash.com/photo-1626785774573-4b799315345d?auto=format&fit=crop&q=80&w=800" },
      { id: 'f2', title: "Веб-интерфейс", cat: "Веб-дизайн", year: 2025, img: "https://images.unsplash.com/photo-1551288049-bbbda5366392?auto=format&fit=crop&q=80&w=800" },
      { id: 'f3', title: "Логотип и стиль", cat: "Логотипы", year: 2025, img: "https://images.unsplash.com/photo-1572044162444-ad60f128bde2?auto=format&fit=crop&q=80&w=800" },
    ],
    archive: [
      { id: 'a1', title: "Учебный логотип", cat: "Логотипы", year: 2024, img: "https://images.unsplash.com/photo-1614850523296-d8c1af93d400?auto=format&fit=crop&q=80&w=800" },
      { id: 'a2', title: "Графическая работа", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1561070791-2526d30994b5?auto=format&fit=crop&q=80&w=800" },
      { id: 'a3', title: "Макет полиграфии", cat: "Печатная графика", year: 2024, img: "https://images.unsplash.com/photo-1586075010923-2dd4570fb338?auto=format&fit=crop&q=80&w=800" },
      { id: 'a4', title: "Первый лендинг", cat: "Веб-дизайн", year: 2024, img: "https://images.unsplash.com/photo-1547658719-da2b51169166?auto=format&fit=crop&q=80&w=800" },
    ]
  }), []);

  const filterFn = (p) => filter === 'Все' || p.cat === filter;
  const filteredFeatured = projects.featured.filter(filterFn);
  const filteredArchive = projects.archive.filter(filterFn);

  useEffect(() => {
    const handleScroll = () => setIsScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const scrollTo = (id) => {
    const el = document.getElementById(id);
    if (el) {
      window.scrollTo({
        top: el.getBoundingClientRect().top + window.pageYOffset - 140,
        behavior: 'smooth'
      });
    }
  };

  return (
    <div style={{ backgroundColor: themeStyles.background, color: themeStyles.text, minHeight: '100vh' }} className="font-sans">
      {/* Подгружаем Tailwind */}
      <link href="https://cdn.jsdelivr.net/npm/tailwindcss@2.2.19/dist/tailwind.min.css" rel="stylesheet" />

      {/* Шапка */}
      <div className="fixed top-0 w-full z-50 flex flex-col">
        <header style={{ backgroundColor: 'rgba(13, 13, 15, 0.9)', borderBottom: '1px solid rgba(255,255,255,0.05)' }} className={`px-6 md:px-12 py-5 backdrop-blur-xl transition-all duration-300 ${isScrolled ? 'py-4' : 'py-6'}`}>
          <div className="max-w-7xl mx-auto flex justify-between items-center">
            <div style={{ color: themeStyles.accent }} className="text-lg font-bold tracking-widest uppercase">
              АЛЕКСАНДРА БЛАГОДАТСКИХ
            </div>

            <nav className="hidden md:flex items-center gap-8 text-[10px] uppercase tracking-widest" style={{ color: 'rgba(255,255,255,0.4)' }}>
              <button onClick={() => scrollTo('projects')} className="hover:text-white transition-colors">Проекты</button>
              <button onClick={() => scrollTo('about')} className="hover:text-white transition-colors">Обо мне</button>
              <button onClick={() => scrollTo('contact')} className="hover:text-white transition-colors">Контакты</button>
            </nav>

            <div className="flex gap-5 items-center">
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="hover:text-[#ffb3d9] transition-all transform hover:scale-110">
                <Icon name="telegram"/>
              </a>
              <a href="tel:+79639960003" className="hover:text-[#ffb3d9] transition-all transform hover:scale-110">
                <Icon name="phone"/>
              </a>
            </div>
          </div>
        </header>

        <div style={{ backgroundColor: 'rgba(13, 13, 15, 0.8)', borderBottom: '1px solid rgba(255,255,255,0.05)' }} className="px-6 md:px-12 py-4 backdrop-blur-lg">
          <div className="max-w-7xl mx-auto flex flex-wrap gap-2">
            {categories.map(cat => (
              <button
                key={cat}
                onClick={() => setFilter(cat)}
                style={filter === cat ? { backgroundColor: themeStyles.accent, color: '#2d1b24', borderColor: themeStyles.accent } : { color: 'rgba(255,255,255,0.4)', borderColor: 'rgba(255,255,255,0.1)', background: 'rgba(255,255,255,0.05)' }}
                className="px-4 py-1.5 rounded-full text-[10px] uppercase tracking-wider transition-all border"
              >
                {cat}
              </button>
            ))}
          </div>
        </div>
      </div>

      {/* Обо мне */}
      <section id="about" className="pt-72 pb-24 px-6 md:px-12">
        <div className="max-w-7xl mx-auto">
          <h1 className="text-5xl md:text-8xl font-serif font-light tracking-tight mb-8 leading-none max-w-4xl" style={{ color: 'white' }}>
            Учусь делать <span style={{ color: themeStyles.accent }} className="italic">красивый</span> и понятный дизайн.
          </h1>
          <p className="max-w-2xl text-xl font-light leading-relaxed" style={{ color: 'rgba(255,255,255,0.4)' }}>
            Привет, я Александра. Изучаю айдентику, логотипы и веб-дизайн. 
            Здесь я собираю свои работы.
          </p>
        </div>
      </section>

      {/* Проекты */}
      <main id="projects" className="max-w-7xl mx-auto px-6 md:px-12 pb-32">
        <div className="mb-24">
          <h2 className="text-[10px] uppercase tracking-[0.4em] mb-10" style={{ color: 'rgba(255,255,255,0.2)' }}>Избранные проекты</h2>
          <div className="grid grid-cols-1 md:grid-cols-2 gap-12">
            {filteredFeatured.map((project) => (
              <div key={project.id} className="group cursor-pointer">
                <div className="relative rounded-3xl overflow-hidden bg-white bg-opacity-5 mb-6 border border-white border-opacity-5 shadow-2xl transition-all duration-500 hover:border-[#ffb3d9]">
                  <img src={project.img} alt={project.title} className="w-full h-auto object-cover transition-transform duration-1000 group-hover:scale-105" />
                </div>
                <div className="flex justify-between items-end px-2">
                  <div>
                    <h3 className="text-xl font-medium mb-1 hover:text-[#ffb3d9] transition-colors">{project.title}</h3>
                    <p className="text-[10px] uppercase tracking-widest" style={{ color: 'rgba(255,255,255,0.3)' }}>{project.cat}</p>
                  </div>
                  <span className="text-[10px]" style={{ color: 'rgba(255,255,255,0.1)' }}>{project.year}</span>
                </div>
              </div>
            ))}
          </div>
        </div>

        <div className="pt-10 border-t border-white border-opacity-5 text-center md:text-left">
          <button 
              onClick={() => setShowArchive(!showArchive)}
              style={{ color: 'rgba(255,255,255,0.4)', borderColor: 'rgba(255,255,255,0.1)', background: 'rgba(255,255,255,0.05)' }}
              className="px-8 py-3 hover:bg-[#ffb3d9] hover:bg-opacity-10 border rounded-full text-[10px] uppercase tracking-[0.4em] hover:text-[#ffb3d9] transition-all"
          >
            {showArchive ? '— Свернуть' : '+ Показать архив'}
          </button>

          {showArchive && (
            <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-8 mt-12">
              {filteredArchive.map((project) => (
                <div key={project.id} className="group">
                  <div className="relative rounded-2xl overflow-hidden aspect-square bg-white bg-opacity-5 mb-4 border border-white border-opacity-5 transition-all">
                      <img src={project.img} alt={project.title} className="w-full h-full object-cover opacity-40 group-hover:opacity-100 transition-opacity duration-500" />
                  </div>
                  <h4 className="text-sm font-medium mb-1" style={{ color: 'rgba(255,255,255,0.6)' }}>{project.title}</h4>
                  <p className="text-[9px] uppercase tracking-widest" style={{ color: 'rgba(255,255,255,0.2)' }}>{project.cat}</p>
                </div>
              ))}
            </div>
          )}
        </div>
      </main>

      <footer id="contact" className="py-24 px-6 md:px-12 border-t border-white border-opacity-5">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row justify-between items-start md:items-end gap-16">
          <div>
            <h2 style={{ color: themeStyles.accent }} className="text-4xl font-serif mb-12 italic">Связаться со мной</h2>
            <div className="flex flex-col gap-6">
              <a href="tel:+79639960003" className="text-2xl font-light hover:text-[#ffb3d9] transition-all border-b border-white border-opacity-5 pb-2 inline-block">8 (963) 996-00-03</a>
              <a href="https://t.me/renraie" target="_blank" rel="noreferrer" className="text-2xl font-light hover:text-[#ffb3d9] transition-all border-b border-white border-opacity-5 pb-2 inline-block">Telegram: @renraie</a>
            </div>
          </div>
          <div className="text-[10px] uppercase tracking-[0.4em]" style={{ color: 'rgba(255,255,255,0.1)' }}>
            © 2024—2026 Alexandra Blagodatskikh
          </div>
        </div>
      </footer>

      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Playfair+Display:ital,wght@0,400;0,700;1,400&display=swap');

        * { box-sizing: border-box; }

        body { 
          margin: 0; 
          padding: 0; 
          background-color: #0d0d0f !important; 
          color: #e0e0e6 !important;
        }

        .font-serif { font-family: 'Playfair Display', serif; }

        /* Гарантированные стили для сетки, если Tailwind не подгрузился */
        .grid { display: grid; }
        .grid-cols-1 { grid-template-columns: repeat(1, minmax(0, 1fr)); }
        @media (min-width: 768px) {
          .grid-cols-2 { grid-template-columns: repeat(2, minmax(0, 1fr)); }
          .lg\\:grid-cols-4 { grid-template-columns: repeat(4, minmax(0, 1fr)); }
        }
      `}</style>
    </div>
  );
};

export default App;
